import { describe, it, expect } from 'vitest'
import ts from 'typescript'
import { generateClientConfig } from '../plugins/client-config.js'

describe('generateClientConfig', () => {
  it('returns filename client-config.ts', () => {
    expect(generateClientConfig().filename).toBe('client-config.ts')
  })

  it('contains the auto-generated header', () => {
    expect(generateClientConfig().content).toContain(
      '// This file is auto-generated by @codewithagents/openapi-gen'
    )
  })

  it('exports ClientConfig interface', () => {
    expect(generateClientConfig().content).toContain('export interface ClientConfig')
  })

  it('exports configureClient function', () => {
    expect(generateClientConfig().content).toContain('export function configureClient')
  })

  it('exports getConfig function', () => {
    expect(generateClientConfig().content).toContain('export function getConfig')
  })

  it('supports token as string or function in interface', () => {
    const content = generateClientConfig().content
    expect(content).toContain('token?')
    expect(content).toContain('Promise<string>')
  })

  it('supports credentials field', () => {
    expect(generateClientConfig().content).toContain('credentials?')
  })

  it('generated content compiles with TypeScript strict mode', () => {
    const content = generateClientConfig().content
    const filename = 'client-config.ts'

    // Use convertCompilerOptionsFromJson so lib names are resolved correctly
    const { options } = ts.convertCompilerOptionsFromJson(
      {
        strict: true,
        target: 'ES2022',
        moduleResolution: 'Bundler',
        noEmit: true,
        skipLibCheck: true,
        lib: ['ES2022', 'DOM'],
      },
      '.'
    )

    const sourceFile = ts.createSourceFile(filename, content, ts.ScriptTarget.ES2022, true)
    const defaultHost = ts.createCompilerHost(options)

    const customHost: ts.CompilerHost = {
      ...defaultHost,
      getSourceFile: (name, lang) =>
        name === filename ? sourceFile : defaultHost.getSourceFile(name, lang),
      fileExists: (name) => name === filename || defaultHost.fileExists(name),
      readFile: (name) => (name === filename ? content : defaultHost.readFile(name)),
    }

    const program = ts.createProgram([filename], options, customHost)
    const diagnostics = ts
      .getPreEmitDiagnostics(program, sourceFile)
      .filter((d) => d.file?.fileName === filename)

    if (diagnostics.length > 0) {
      const messages = diagnostics
        .map((d) => ts.flattenDiagnosticMessageText(d.messageText, '\n'))
        .join('\n')
      throw new Error(`TypeScript errors in generated client-config.ts:\n${messages}`)
    }

    expect(diagnostics.length).toBe(0)
  })
})
